import anthropic
import json

client = anthropic.Anthropic()

TOOLS = [
    {
        "name": "search_orders",
        "description": "Search a customer's order history by order ID or date range.",
        "input_schema": {
            "type": "object",
            "properties": {
                "query": {"type": "string", "description": "Order ID or date in YYYY-MM-DD format."},
            },
            "required": ["query"],
        },
    },
    {
        "name": "get_account_info",
        "description": "Retrieve account details (name, email, subscription tier) for the current user.",
        "input_schema": {"type": "object", "properties": {}, "required": []},
    },
]


def call(user_message: str, tool_choice=None) -> dict:
    kwargs = {
        "model": "claude-haiku-4-5-20251001",
        "max_tokens": 300,
        "tools": TOOLS,
        "messages": [{"role": "user", "content": user_message}],
    }
    if tool_choice:
        kwargs["tool_choice"] = tool_choice
    response = client.messages.create(**kwargs)
    tool_calls = [
        {"name": b.name, "input": b.input}
        for b in response.content if b.type == "tool_use"
    ]
    text = next((b.text for b in response.content if hasattr(b, "text")), None)
    return {"tool_calls": tool_calls, "text": text, "stop_reason": response.stop_reason}


# --- Default: model decides whether to call a tool ---
print("Default (auto):")
result = call("What is my subscription tier?")
print(f"  Tool calls: {result['tool_calls']}")
print(f"  Text: {result['text']}")

# --- Force a specific tool regardless of message ---
print("\nForced (specific):")
result = call(
    "Hello!",
    tool_choice={"type": "tool", "name": "get_account_info"},
)
print(f"  Tool calls: {result['tool_calls']}")

# --- Force some tool to be called (model picks which) ---
print("\nForced (any):")
result = call(
    "What's my order status?",
    tool_choice={"type": "any"},
)
print(f"  Tool calls: {result['tool_calls']}")

# --- Prevent any tool call ---
print("\nNo tools (none):")
result = call(
    "What is my subscription tier?",
    tool_choice={"type": "none"},
)
print(f"  Text: {result['text']}")

import anthropic

client = anthropic.Anthropic()

# Two search tools with adjacent scopes — descriptions disambiguate them
OVERLAPPING_TOOLS = [
    {
        "name": "search_product_catalogue",
        "description": (
            "Searches the product catalogue for items, prices, and availability. "
            "Use when the user asks about products, SKUs, stock, or pricing. "
            "Does NOT search orders, accounts, or support history."
        ),
        "input_schema": {
            "type": "object",
            "properties": {
                "query": {"type": "string", "description": "Product name, SKU, or category."},
            },
            "required": ["query"],
        },
    },
    {
        "name": "search_support_articles",
        "description": (
            "Searches the help centre for how-to articles, FAQs, and troubleshooting guides. "
            "Use when the user has a how-to question or reports a problem. "
            "Does NOT search the product catalogue or order history."
        ),
        "input_schema": {
            "type": "object",
            "properties": {
                "query": {"type": "string", "description": "Support question or error description."},
            },
            "required": ["query"],
        },
    },
]

TEST_MESSAGES = [
    "How do I reset my password?",
    "Do you have the blue jacket in size M?",
    "I'm getting an error when I try to checkout.",
]

for msg in TEST_MESSAGES:
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=150,
        tools=OVERLAPPING_TOOLS,
        messages=[{"role": "user", "content": msg}],
    )
    tool_calls = [b.name for b in response.content if b.type == "tool_use"]
    print(f"'{msg}'")
    print(f"  → {tool_calls if tool_calls else 'no tool'}")

import anthropic
from dataclasses import dataclass
from typing import Optional

client = anthropic.Anthropic()

TOOLS = [
    {
        "name": "get_order_status",
        "description": (
            "Look up the status and tracking info for a specific order by order ID. "
            "Use when the user asks about a specific order, shipment, delivery, or tracking number. "
            "Does NOT look up account details, product info, or handle complaints."
        ),
        "input_schema": {
            "type": "object",
            "properties": {
                "order_id": {"type": "string", "description": "The order ID (format: ORD-XXXXX)."},
            },
            "required": ["order_id"],
        },
    },
    {
        "name": "get_account_info",
        "description": (
            "Retrieve account details for the current user: name, email, subscription tier, payment method. "
            "Use when the user asks about their account, subscription, billing, or payment details. "
            "Does NOT look up order history — use get_order_status for that."
        ),
        "input_schema": {"type": "object", "properties": {}, "required": []},
    },
    {
        "name": "search_catalogue",
        "description": (
            "Search the product catalogue for items by name, SKU, or category. Returns prices and stock. "
            "Use when the user asks about products, availability, pricing, or specifications. "
            "Does NOT search orders, accounts, or help articles."
        ),
        "input_schema": {
            "type": "object",
            "properties": {
                "query": {"type": "string", "description": "Product name, SKU, or category."},
            },
            "required": ["query"],
        },
    },
    {
        "name": "escalate_complaint",
        "description": (
            "Create a complaint ticket and escalate to a human support agent. "
            "Use when: the user expresses dissatisfaction, reports a problem not resolvable by lookup, "
            "asks to speak to a human, or repeats a question after an unsatisfactory answer. "
            "Do NOT use for general information requests."
        ),
        "input_schema": {
            "type": "object",
            "properties": {
                "reason": {"type": "string", "description": "Brief summary of the complaint."},
                "urgency": {"type": "string", "enum": ["low", "medium", "high"]},
            },
            "required": ["reason", "urgency"],
        },
    },
]

SYSTEM = """You are a customer support agent for an e-commerce store.

Tool selection policy:
1. Answer from your own knowledge first for general questions (store hours, return policy, etc).
2. Only call a tool when live data is required.
3. Verify account (get_account_info) before accessing subscription-gated order history.
4. If a user is frustrated or asks to speak to a human, always escalate — do not attempt to resolve.
5. Never call two tools in one turn. If two pieces of information are needed, ask a clarifying question first.
"""


@dataclass
class SelectionResult:
    user_message: str
    selected_tool: Optional[str]
    tool_input: Optional[dict]
    text_response: Optional[str]
    stop_reason: str


def run_agent_turn(user_message: str) -> SelectionResult:
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=300,
        system=SYSTEM,
        tools=TOOLS,
        messages=[{"role": "user", "content": user_message}],
    )
    tool_use = next((b for b in response.content if b.type == "tool_use"), None)
    text     = next((b.text for b in response.content if hasattr(b, "text")), None)
    return SelectionResult(
        user_message=user_message,
        selected_tool=tool_use.name if tool_use else None,
        tool_input=tool_use.input if tool_use else None,
        text_response=text,
        stop_reason=response.stop_reason,
    )


# Selection test suite
TEST_CASES = [
    ("What are your store hours?",                   None),              # General knowledge
    ("Where is my order ORD-12345?",                 "get_order_status"),
    ("What subscription tier am I on?",              "get_account_info"),
    ("Do you have the blue hoodie in size L?",       "search_catalogue"),
    ("This is unacceptable, I want to speak to someone", "escalate_complaint"),
]

print(f"{'Message':<45} {'Expected':<22} {'Got':<22} {'Pass'}")
print("-" * 100)
for msg, expected_tool in TEST_CASES:
    result = run_agent_turn(msg)
    got   = result.selected_tool or "(no tool)"
    exp   = expected_tool or "(no tool)"
    passed = got == exp
    print(f"{msg[:44]:<45} {exp:<22} {got:<22} {'✓' if passed else '✗'}")
